/// <summary>
///
/// </summary>
/// <param name = "_this"></param>
/// <returns></returns>

[SysClientCacheDataMethodAttribute(true)]
public static display str ledgerOffsetCode(CustTrans _this)
{
    DimensionAttributeLevelValueAllView dimAttriView;
    DimensionAttribute                  dimAttri;
    str mainAccount;

    select DisplayValue from dimAttriView
        where dimAttriView.ValueCombinationRecId == _this.DefaultDimension
        join BackingEntityType from dimAttri
        where dimAttri.RecId == dimAttriView.DimensionAttribute
        && dimAttri.Name == "MainAccount";

    if(dimAttriView)
    {
        mainAccount = dimAttriView.DisplayValue;
    }
    return mainAccount;
}

/// <summary>
///
/// </summary>
/// <param name = "_this"></param>
/// <returns></returns>
[SysClientCacheDataMethodAttribute(true)]
public static display AccountName ledgerOffsetName(CustTrans _this)
{
    DimensionAttributeLevelValueAllView dimAttriView;
    DimensionAttribute                  dimAttri;
    AccountName mainAccountName;
    MainAccount mainAccountOrg;

    select DisplayValue from dimAttriView
        where dimAttriView.ValueCombinationRecId == _this.DefaultDimension
        join BackingEntityType from dimAttri
        where dimAttri.RecId == dimAttriView.DimensionAttribute
        && dimAttri.Name == "MainAccount";

    if(dimAttriView)
    {
        select * from mainAccountOrg 
            where mainAccountOrg.MainAccountId == dimAttriView.DisplayValue;
        if(mainAccountOrg)
       {
           mainAccountName = mainAccountOrg.Name;
       }
    }
    return mainAccountName;
}

/// <summary>
///
/// </summary>
/// <param name = "_this"></param>
/// <returns></returns>
[SysClientCacheDataMethodAttribute(true)]
public static display AmountCurDebCred balanceTC(CustTrans _this)
{
    AmountCurDebCred balance;

    balance = _this.AmountCur - _this.SettleAmountCur;

    return balance;
}

/// <summary>
///
/// </summary>
/// <param name = "_this"></param>
/// <returns></returns>
[SysClientCacheDataMethodAttribute(true)]
public static display AmountMSTDebCred balanceUSD(CustTrans _this)
{
    AmountMSTDebCred balanceUSDOrg;

    AmountCurDebCred balance;

    balance = _this.AmountCur - _this.SettleAmountCur;

    ExchRate newExchRate, newExchRateOrg;

    if(_this.LastExchAdjRate)
    {
        newExchRate = _this.LastExchAdjRate;
    }
    else
    {
        newExchRate = _this.ExchRate;
    }
    if(newExchRate)
    {
        newExchRateOrg = newExchRate/100;
    }
    balanceUSDOrg = (balance * newExchRateOrg);

    return balanceUSDOrg;
}

/// <summary>
///
/// </summary>
/// <param name = "_this"></param>
/// <returns></returns>
[SysClientCacheDataMethodAttribute(true)]
public static display ExchRate newExchangeRate(CustTrans _this)
{
    ExchRate newExchRate, newExchRateOrg;

    if(_this.LastExchAdjRate)
    {
        newExchRate = _this.LastExchAdjRate;
    }
    else
    {
        newExchRate = _this.ExchRate;
    }
    if(newExchRate)
    {
        newExchRateOrg = newExchRate/100;
    }

    return newExchRateOrg;
}

